final:
module edge_detector (
    input wire clk,
    input wire signal_in,
    output reg signal_out
);

reg signal_in_prev;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    signal_out <= (signal_in && !signal_in_prev);
    signal_in_prev <= signal_in;
end

endmodule
